package ui.librarian;
import database.LibraryRepository;import model.DisplayIds;import database.LibraryRepository.HoldRow;import javafx.beans.property.*;import javafx.collections.*;import javafx.fxml.FXML;import javafx.scene.control.*;import java.sql.SQLException;
public class HoldsController extends NavigationController{@FXML private TableView<HoldRow> table;@FXML private TableColumn<HoldRow,String> idCol,memberCol,titleCol,statusCol,queueCol;@FXML private Label count;private final LibraryRepository repo=new LibraryRepository();@FXML private void initialize(){idCol.setCellValueFactory(v->new ReadOnlyStringWrapper(DisplayIds.shortId("h",v.getValue().id())));memberCol.setCellValueFactory(v->new ReadOnlyStringWrapper(v.getValue().member()));titleCol.setCellValueFactory(v->new ReadOnlyStringWrapper(v.getValue().title()));statusCol.setCellValueFactory(v->new ReadOnlyStringWrapper(capitalize(v.getValue().status())));queueCol.setCellValueFactory(v->new ReadOnlyStringWrapper("#"+v.getValue().queuePosition()));refresh();}private String capitalize(String value){return value==null||value.isBlank()?"Unknown":value.substring(0,1).toUpperCase()+value.substring(1).toLowerCase();}@FXML private void refresh(){try{var rows=repo.findHolds("");table.setItems(FXCollections.observableArrayList(rows));count.setText(rows.isEmpty()?"No holds have been placed yet.":rows.size()+" hold record"+(rows.size()==1?"":"s"));}catch(SQLException e){showError("Holds could not be loaded",e);}}@FXML private void cancel(){var row=table.getSelectionModel().getSelectedItem();if(row==null){new Alert(Alert.AlertType.INFORMATION,"Select a hold first.").showAndWait();return;}try{repo.cancelHold(row.id());refresh();}catch(SQLException e){showError("The hold could not be cancelled",e);}}}
